# Track B: small cities 5K–50K population (onboarding target for SaaS $1K–2K/mo, Custom Report $15–30K)
TRACK_B_POP_MIN = 5_000
TRACK_B_POP_MAX = 50_000


def get_track_b_cities():
    """Return municipalities in Track B population band (5K–50K). For onboarding and SaaS tier eligibility."""
    by_id = {}
    for c in TEXAS_COMMUNITIES.values():
        pop = c.get("population") or 0
        if TRACK_B_POP_MIN <= pop <= TRACK_B_POP_MAX:
            by_id[c["id"]] = {**c, "population_band": "track_b"}
    for c in DEMO_COMMUNITIES.values():
        pop = c.get("population") or 0
        if TRACK_B_POP_MIN <= pop <= TRACK_B_POP_MAX and c["id"] not in by_id:
            by_id[c["id"]] = {**c, "population_band": "track_b"}
    return list(by_id.values())
